import { navigateToUrl } from 'single-spa';
import { normalizeNavPath } from './resolveNavTitle';
import { runWithLeaveGuard } from '@linm-soft-org/linm-web-common-components';

export const LINM_NAV_FORCE_PATH_EVENT = 'linm:nav:force-path';

/**
 * Sidebar / topbar menu click — clear workspace document tabs then navigate.
 * ShellWorkspaceTabProvider listens and resets tab bar + --workspace-tab-height.
 */
export const LINM_NAV_SIDEBAR_NAVIGATE_EVENT = 'linm:nav:sidebar-navigate';

export type ForcePathDetail = {
  path: string;
  /** When true, MemoryRouter must use path as-is (no append window.search). */
  exact?: boolean;
};

export type ShellNavigateOptions = {
  /** Clear workspace tabs (sidebar menu only). Default false. */
  resetTabs?: boolean;
  /** Skip leave-guard (internal tab switch after guard already passed). */
  skipLeaveGuard?: boolean;
};

function dispatchSidebarNavigate(targetPath: string): void {
  window.dispatchEvent(
    new CustomEvent(LINM_NAV_SIDEBAR_NAVIGATE_EVENT, {
      detail: { path: targetPath },
    }),
  );
}

function dispatchForcePath(targetPath: string): void {
  window.dispatchEvent(
    new CustomEvent(LINM_NAV_FORCE_PATH_EVENT, {
      detail: { path: targetPath, exact: true } satisfies ForcePathDetail,
    }),
  );
}

/**
 * Shell content navigation — URL bar + MFE MemoryRouter must both update.
 *
 * Nav title uses window.location (useShellPathname). Content uses MemoryRouter.
 * Without `force-path`, window can show /kt/pt/:id while Outlet still renders
 * the previous page (e.g. Sổ tổng hợp) — Figure 1 bug.
 */
export function shellNavigateTo(path: string, options?: ShellNavigateOptions): void {
  const target = normalizeNavPath(path.split('?')[0] || path);
  const search = path.includes('?') ? path.slice(path.indexOf('?')) : '';
  const full = `${target}${search}`;

  const run = () => {
    if (options?.resetTabs) {
      dispatchSidebarNavigate(target);
    }
    // Always push shell URL (even when pathname equal — remount / query change).
    navigateToUrl(full);
    // Force MemoryRouter in the active MFE. Use target path (exact) so sync does not
    // depend on timing of window.location vs routing-event.
    window.setTimeout(() => {
      dispatchForcePath(full.includes('?') ? full : target);
    }, 0);
    // Second tick — MFE may mount after first force-path (cross-MFE switch).
    window.setTimeout(() => {
      dispatchForcePath(full.includes('?') ? full : target);
    }, 50);
  };

  if (options?.skipLeaveGuard) {
    run();
    return;
  }
  runWithLeaveGuard(target, run);
}

/**
 * Sidebar / topbar menu — reset tabs + navigate + force MemoryRouter sync.
 */
export function forceShellNavigate(targetPath: string, _currentPathname?: string): void {
  shellNavigateTo(targetPath, { resetTabs: true });
}
